import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

function ClientDashboard() {
  const [project, setProject] = useState(null);
  const navigate = useNavigate();

  // 1. Check if user is already logged in when the page loads
  useEffect(() => {
    const loggedInUser = localStorage.getItem('clientUser');
    if (loggedInUser) {
      setProject(JSON.parse(loggedInUser));
    } else {
      // If no user found, send them to the separate Login page
      alert("Please login first to view your dashboard.");
      navigate('/login'); 
    }
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('clientUser');
    navigate('/login');
  };

  if (!project) return null; // Don't show anything until data is loaded

  return (
    <div className="container py-5 mt-5">
      <div className="row justify-content-center">
        <div className="col-lg-8">
          <div className="card shadow-lg border-0 rounded-4 overflow-hidden">
            
            {/* Header with Logout */}
            <div className="bg-primary p-4 text-white d-flex justify-content-between align-items-center">
              <h4 className="mb-0 fw-bold">Welcome, {project.fullName}!</h4>
              <button className="btn btn-sm btn-outline-light px-3 fw-bold" onClick={handleLogout}>
                Logout
              </button>
            </div>
            
            <div className="card-body p-4 p-lg-5">
              <div className="row g-4 mb-4 text-center">
                <div className="col-md-6">
                  <div className="p-3 border rounded-3 bg-light">
                    <small className="text-muted d-block">Project Type</small>
                    <h5 className="fw-bold text-dark">{project.serviceType}</h5>
                  </div>
                </div>
                <div className="col-md-6">
                  <div className="p-3 border rounded-3 bg-light">
                    <small className="text-muted d-block">Payment Status</small>
                    <h5 className={`fw-bold ${project.paymentStatus === 'Paid' ? 'text-success' : 'text-danger'}`}>
                      {project.paymentStatus}
                    </h5>
                  </div>
                </div>
              </div>

              {/* Progress Bar Section */}
              <div className="mb-4">
                <div className="d-flex justify-content-between mb-2">
                  <h6 className="fw-bold">Project Progress</h6>
                  <span className="fw-bold text-primary">{project.progress}%</span>
                </div>
                <div className="progress rounded-pill shadow-sm" style={{ height: '25px' }}>
                  <div 
                    className="progress-bar progress-bar-striped progress-bar-animated bg-success" 
                    style={{ width: `${project.progress}%` }}
                  ></div>
                </div>
                <p className="mt-3 text-muted">Current Work Status: <strong>{project.status}</strong></p>
              </div>

              {/* Financial Summary */}
              <div className="alert alert-info border-0 rounded-3 d-flex justify-content-between align-items-center">
                <span>Remaining Balance: <strong>₹{project.totalBudget - project.advancePaid}</strong></span>
                <span className="small text-muted">Total Budget: ₹{project.totalBudget}</span>
              </div>
            </div>

          </div>
        </div>
      </div>
    </div>
  );
}

export default ClientDashboard;
